export default function LessonPage() {
  const t = useTranslations('lesson')
  const params = useParams()
  const courseId = params.id as string
  const lessonIdx = parseInt(params.lessonIndex as string) - 1
  const course = COURSES[courseId]

  const { markComplete, toggleComplete, isComplete, completedCount, hydrated } = useProgress(courseId)
  const locale = useLocale()
  const cn = useTranslations('courseNames')
  const getCourseTitle = () => { try { const v = cn(`${courseId}.title`); return v.includes('.title') ? course?.title : v } catch { return course?.title } }
  const ln = useTranslations('lessonNames')
  const getLessonTitle = (idx: number) => { try { const v = ln(`${courseId}.${idx}`); return v.includes(`${courseId}.`) ? course?.lessons[idx]?.title : v } catch { return course?.lessons[idx]?.title } }
  const lessonCompleted = isComplete(lessonIdx + 1)

  const [chatOpen, setChatOpen] = useState(false)
  const [messages, setMessages] = useState<{role: string; content: string}[]>([])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(false)
  const chatEndRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  if (!course || lessonIdx < 0 || lessonIdx >= course.lessons.length) {
    return (
      <div className="max-w-3xl mx-auto px-4 py-16 text-center">
        <h1 className="text-2xl font-bold">{t('notFound')}</h1>
        <Link href="/courses" className="text-primary-700 hover:underline mt-4 inline-block">&larr; {t('backToCourses')}</Link>
      </div>
    )
  }

  const lesson = course.lessons[lessonIdx]
  const prevLesson = lessonIdx > 0 ? lessonIdx : null
  const nextLesson = lessonIdx < course.lessons.length - 1 ? lessonIdx + 2 : null

  async function sendMessage() {
    if (!input.trim()) return
    const userMsg = input.trim()
    setInput('')
    const newMessages = [...messages, { role: 'user', content: userMsg }]
    setMessages(newMessages)
    setLoading(true)

    try {
      const response = await fetch('/api/bible-chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          messages: newMessages,
          lessonContext: {
            courseTitle: course.title,
            lessonTitle: lesson.title,
            bibleRefs: lesson.refs,
            content: lesson.content,
          },
        }),
      })

      const data = await response.json()
      if (!response.ok) {
        setMessages(prev => [...prev, { role: 'assistant', content: data.error || 'Sorry, I could not respond. Please try again.' }])
        setLoading(false)
        return
      }

      setMessages(prev => [...prev, { role: 'assistant', content: data.message }])
    } catch {
      setMessages(prev => [...prev, { role: 'assistant', content: 'Connection error. Please try again.' }])
    }
    setLoading(false)
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-sm text-gray-500 mb-6 flex-wrap">
        <Link href="/courses" className="hover:text-primary-700">{t('courses')}</Link>
        <span>/</span>
        <Link href={`/courses/${courseId}`} className="hover:text-primary-700">{getCourseTitle()}</Link>
        <span>/</span>
        <span className="text-secondary-900 font-medium">{t('lessonNum', { num: lessonIdx + 1 })}</span>
      </div>

      {/* Lesson Header */}
      <div className="mb-8">
        <div className="flex items-center gap-3 mb-3">
          <span className="flex-shrink-0 w-10 h-10 bg-primary-500 text-white rounded-full flex items-center justify-center font-bold">
            {lessonIdx + 1}
          </span>
          <div>
            <h1 className="text-2xl font-bold text-secondary-900">{getLessonTitle(lessonIdx) || lesson.title}</h1>
            <p className="text-sm text-primary-600 font-mono mt-0.5">{lesson.refs}</p>
          </div>
        </div>
      </div>

      {/* Progress */}
      <div className="mb-4">
        <div className="flex items-center justify-between text-xs text-gray-500 mb-1">
          <span>{t('progress')}</span>
          <span className="font-semibold">{completedCount}/{course.lessons.length}</span>
        </div>
        <div className="w-full bg-gray-200 rounded-full h-2.5">
          <div className="bg-green-500 h-2.5 rounded-full transition-all duration-500" style={{ width: `${(completedCount / course.lessons.length) * 100}%` }} />
        </div>
      </div>

      {/* Audio Bible */}
      <div className="mb-4">
        <AudioBible bibleRef={lesson.refs} />
      </div>

      {/* Lesson Content */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-8 mb-8">
        <div className="prose prose-sm max-w-none text-gray-700 whitespace-pre-line leading-relaxed">
          {lesson.content}
        </div>
      </div>

      {/* Mark Complete */}
      <button
        onClick={() => toggleComplete(lessonIdx + 1)}
        className={`w-full py-3 border-2 rounded-xl font-medium transition flex items-center justify-center gap-2 mb-6 ${
          lessonCompleted
            ? 'bg-green-100 border-green-300 text-green-800 hover:bg-green-50'
            : 'bg-green-50 border-green-200 text-green-700 hover:bg-green-100'
        }`}
      >
        {lessonCompleted ? <CheckCircle className="w-5 h-5" /> : <Circle className="w-5 h-5" />}
        {lessonCompleted ? t('completed') : t('markComplete')}
      </button>

      {/* Navigation */}
      <div className="flex items-center justify-between mb-8">
        {prevLesson !== null ? (
          <Link href={`/courses/${courseId}/${prevLesson}`} className="flex items-center gap-2 px-4 py-2 border border-gray-200 rounded-lg text-sm hover:bg-gray-50 transition">
            <ChevronLeft className="w-4 h-4" /> {t('prevLesson')}
          </Link>
        ) : <div />}
        
        {nextLesson !== null ? (
          <Link href={`/courses/${courseId}/${nextLesson}`} className="flex items-center gap-2 px-4 py-2 bg-secondary-600 text-white rounded-lg text-sm hover:bg-secondary-700 transition">
            {t('nextLesson')} <ChevronRight className="w-4 h-4" />
          </Link>
        ) : (
          <Link href={`/courses/${courseId}`} className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg text-sm hover:bg-green-700 transition">
            <CheckCircle className="w-4 h-4" /> {t('completeCourse')}
          </Link>
        )}
      </div>

      {/* AI Chat Toggle */}
      <button
        onClick={() => setChatOpen(!chatOpen)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-primary-500 text-white rounded-full shadow-lg hover:bg-primary-600 transition flex items-center justify-center z-40"
      >
        {chatOpen ? <X className="w-6 h-6" /> : <MessageCircle className="w-6 h-6" />}
      </button>

      {/* AI Chat Panel */}
      {chatOpen && (
        <div className="fixed bottom-24 right-6 w-96 max-w-[calc(100vw-3rem)] h-[500px] bg-white rounded-2xl shadow-2xl border border-gray-200 flex flex-col z-40 overflow-hidden">
          {/* Chat Header */}
          <div className="px-4 py-3 bg-gradient-to-r from-primary-500 to-secondary-600 text-white flex items-center gap-2">
            <Sparkles className="w-5 h-5" />
            <span className="font-semibold text-sm">{t('aiTutor')}</span>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {messages.length === 0 && (
              <div className="text-center text-gray-400 text-sm py-8">
                <Sparkles className="w-8 h-8 mx-auto mb-2 text-primary-300" />
                <p>{t('aiWelcome')}</p>
                <p className="text-xs mt-1">{t('aiContext', { lesson: lesson.title })}</p>
              </div>
            )}
            {messages.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] rounded-xl px-3 py-2 text-sm whitespace-pre-line ${
                  msg.role === 'user' ? 'bg-secondary-600 text-white' : 'bg-gray-100 text-gray-700'
                }`}>
                  {msg.content}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-gray-100 rounded-xl px-3 py-2 text-sm text-gray-500 animate-pulse">
                  {t('aiThinking')}...
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input */}
          <div className="p-3 border-t">
            <form onSubmit={(e) => { e.preventDefault(); sendMessage() }} className="flex gap-2">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder={t('aiPlaceholder')}
                className="flex-1 px-3 py-2 border rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary-400"
              />
              <button type="submit" disabled={loading || !input.trim()} className="p-2 bg-primary-500 text-white rounded-lg hover:bg-primary-600 disabled:opacity-50 transition">
                <Send className="w-4 h-4" />
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}
